import React, { useState, useEffect } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import listPlugin from '@fullcalendar/list';
import interactionPlugin from '@fullcalendar/interaction'; 
import axios from 'axios';

const handleCapacityFilterChange = (e) => {
  const value = e.target.value;
  if (value === ">2000") {
    // Handle the case for ">2000" specifically
    setFilters(prevState => ({
      ...prevState,
      maxCapacity: null,  // No upper limit
      minCapacity: 2001,  // Set the minimum limit to 2001
    }));
  } else if (value === "<150") {
    // Handle the "<150" case
    setFilters(prevState => ({
      ...prevState,
      maxCapacity: 149,  // Set the maximum to 149
      minCapacity: null,  // No minimum limit
    }));
  } else if (value.includes("-")) {
    // Handle ranges like "150-350", "350-500", etc.
    const [min, max] = value.split("-");
    setFilters(prevState => ({
      ...prevState,
      minCapacity: parseInt(min),
      maxCapacity: parseInt(max),
    }));
  }
};

const Calendar = () => {
  const [events, setEvents] = useState([]);  
  const [modalVisible, setModalVisible] = useState(false);  
  const [selectedEvent, setSelectedEvent] = useState(null);  
  const [filters, setFilters] = useState({
    venues: [],
    minCapacity: null,
    maxCapacity: null,
    filterByCapacity: false,
  });
  const [venues, setVenues] = useState([]);  
  const [dropdownOpen, setDropdownOpen] = useState(false);  
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    axios.get('http://127.0.0.1:3001/events')
      .then(response => {
        // Map the API response to include the necessary data
        const formattedEvents = response.data.map(event => ({
          id: event.id,
          title: `${event.title} - ${event.venue}`,
          start: new Date(event.start).toISOString(),
          description: event.description,
          venue: event.venue,
          url: event.url,
          flyerImage: event.flyerImage,
          minCapacity: event.minCapacity,  // Ensure min_capacity is included
          maxCapacity: event.maxCapacity   // Ensure max_capacity is included
        }));

        // Log formatted events to see their structure
        console.log('Formatted Events:', formattedEvents);

        // Get unique venues
        const uniqueVenues = [...new Set(formattedEvents.map(event => event.venue))];

        // Set events and venue data
        setEvents(formattedEvents);
        setVenues(uniqueVenues);
      })
      .catch(error => {
        console.error('Error fetching events:', error);
      });
  }, []);

  const handleEventClick = (info) => {
    info.jsEvent.preventDefault();  // Prevent link default behavior
    setSelectedEvent(info.event);  // Set the clicked event to state
    setModalVisible(true);  // Show the modal
  };

  const closeModal = () => {
    setModalVisible(false);  // Hide the modal
    setSelectedEvent(null);  // Clear the selected event
  };

  const handleFilterChange = (e) => {
    const { value, checked } = e.target;
    setFilters(prevState => {
      let updatedVenues = [...prevState.venues];
      if (checked) {
        updatedVenues.push(value);  // Add selected venue
      } else {
        updatedVenues = updatedVenues.filter(venue => venue !== value);  // Remove unselected venue
      }
      return { ...prevState, venues: updatedVenues };
    });
  };

  // Filter events based on the selected venues and capacities
  const filteredEvents = events.filter(event => {
    console.log('Filtered Event:', event); // Log events during filtering to make sure they're not getting filtered out
    const venueMatch = filters.venues.length === 0 || filters.venues.includes(event.venue);
    const searchMatch =
      (event.title || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
      (event.description || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
      (event.venue || '').toLowerCase().includes(searchTerm.toLowerCase());

    const sizeMatch =
      (filters.filterByCapacity && (
        (filters.minCapacity === null || event.minCapacity >= filters.minCapacity) &&
        (filters.maxCapacity === null || event.maxCapacity <= filters.maxCapacity)
      )) || !filters.filterByCapacity;

    return venueMatch && searchMatch && sizeMatch;
  });

  // Reset filters and search term
  const resetFilter = () => {
    setFilters({ venues: [], minCapacity: null, maxCapacity: null, filterByCapacity: false });
    setSearchTerm('');
  };

  return (
    <div className="container">
      <div className="search-filter-container">
        {/* Search Field */}
        <div>
          <label>Search Events:</label>
          <input 
            type="text" 
            placeholder="Search by band, venue, or description"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}  // Update search term
          />
        </div>

        {/* Venue Filter */}
        <div className="filters">
          <label>Filter by Venue:</label>
          <div className="dropdown">
            <button onClick={() => setDropdownOpen(!dropdownOpen)} className="dropdown-btn">
              Select Venues
            </button>
            {dropdownOpen && (
              <div className="dropdown-content">
                {venues.map((venue, index) => (
                  <label key={index}>
                    <input
                      type="checkbox"
                      value={venue}
                      checked={filters.venues.includes(venue)}
                      onChange={handleFilterChange}
                    />
                    {venue}
                  </label>
                ))}
              </div>
            )}
          </div>

{/* Capacity Range Filter */}
<div>
  <label>Filter by Capacity:</label>
  <select onChange={handleCapacityFilterChange}>
    <option value="">Select Capacity Range</option>
    <option value="<150">Under 150</option>
    <option value="150-350">150 - 350</option>
    <option value="350-500">350 - 500</option>
    <option value="500-1000">500 - 1000</option>
    <option value="1000-2000">1000 - 2000</option>
    <option value=">2000">Over 2000</option>
  </select>
</div>

          {/* Toggle filter by capacity */}
          <div>
            <label>
              <input 
                type="radio"
                name="filterByCapacity"
                value="true"
                checked={filters.filterByCapacity === true}
                onChange={() => setFilters(prevState => ({ ...prevState, filterByCapacity: true }))}
              />
              Filter by Capacity
            </label>
            <label>
              <input 
                type="radio"
                name="filterByCapacity"
                value="false"
                checked={filters.filterByCapacity === false}
                onChange={() => setFilters(prevState => ({ ...prevState, filterByCapacity: false }))}
              />
              Filter by Venue
            </label>
          </div>

          <button onClick={resetFilter}>Reset Filter</button>
        </div>
      </div>

    {/* FullCalendar Component */}
    <div className="calendar-container">
      <FullCalendar
        plugins={[dayGridPlugin, timeGridPlugin, listPlugin, interactionPlugin]}
        initialView="dayGridMonth"
        events={filteredEvents}  // This will display the filtered events
        eventClick={handleEventClick}  // Handle event click for modal
        headerToolbar={{
          left: 'prev,next today',
          center: 'title',
          right: 'dayGridMonth,timeGridWeek,timeGridDay,listWeek',  // Calendar views
        }}
      />
    </div>

{/* Modal for event details */}
{modalVisible && selectedEvent && (
  <div style={modalStyles.overlay} onClick={closeModal}>
    <div style={modalStyles.modal} onClick={(e) => e.stopPropagation()}>
      <h3>{selectedEvent.title}</h3>
      <p><strong>Venue:</strong> {selectedEvent.extendedProps.venue}</p>
      <p><strong>Description:</strong> {selectedEvent.extendedProps.description}</p>
      <p><strong>Event Link:</strong> <a href={selectedEvent.url} target="_blank" rel="noopener noreferrer">{selectedEvent.url}</a></p>

      {/* Show Capacity */}
      <p><strong>Capacity: </strong>
        {selectedEvent.extendedProps.minCapacity === selectedEvent.extendedProps.maxCapacity
          ? `${selectedEvent.extendedProps.minCapacity}`  // If min and max are the same, show just one number
          : `${selectedEvent.extendedProps.minCapacity} - ${selectedEvent.extendedProps.maxCapacity}`}  {/* If they are different, show a range */}
      </p>

      <button onClick={closeModal}>Close</button>
    </div>
  </div>
)}
  </div>
);
};

// Simple modal styling
const modalStyles = {
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    backgroundColor: 'rgba(0, 0, 0, 0.5)',  // Scrim background color with opacity
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,  // Ensure the modal is above other content
  },
  modal: {
    backgroundColor: 'white',  // Modal itself is opaque
    padding: '20px',
    borderRadius: '8px',
    width: '300px',
    textAlign: 'center',
    zIndex: 1001,  // Ensure modal is above overlay
  }
};

export default Calendar;
